        "github.com/pkg/errors"
 )

@@ -41,10 +40,7 @@ func WithLocation(err error, location []Range) error {
        if errors.As(err, &el) {
                return err
        }
-       return stack.Enable(&ErrorLocation{
-               error:    err,
-               Location: location,
